import heapq
import math

def agent_step(state, history):
    def heuristic(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def a_star_search(start, goal, walls, blocks, historical_obstacles):
        effective_blocks = blocks.copy()
        effective_blocks.update(historical_obstacles)  # Merge historical failed moves as obstacles
        frontier = []
        heapq.heappush(frontier, (0, start))
        came_from = {}
        cost_so_far = {}
        came_from[start] = None
        cost_so_far[start] = 0

        while frontier:
            _, current = heapq.heappop(frontier)

            if current == goal:
                break

            for dx, dy in [(-3, 0), (3, 0), (0, -3), (0, 3)]:
                next_step = (current[0] + dx, current[1] + dy)
                if next_step in walls or next_step in effective_blocks:
                    continue
                new_cost = cost_so_far[current] + 1
                if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                    cost_so_far[next_step] = new_cost
                    priority = new_cost + heuristic(goal, next_step)
                    heapq.heappush(frontier, (priority, next_step))
                    came_from[next_step] = current

        # Reconstruct path
        current = goal
        path = []
        while current != start and current in came_from:
            path.append(current)
            current = came_from.get(current)
        path.reverse()
        return path if path else None  # Ensure path is valid

    def get_move_direction(from_pos, to_pos):
        if from_pos[0] < to_pos[0]:
            return "MOVE_RIGHT"
        elif from_pos[0] > to_pos[0]:
            return "MOVE_LEFT"
        elif from_pos[1] < to_pos[1]:
            return "MOVE_DOWN"
        elif from_pos[1] > to_pos[1]:
            return "MOVE_UP"
        return None

    def is_stuck(history):
        return len(history) >= 3 and not any(turn["moved"] for turn in history[-3:])

    def get_historical_obstacles(history):
        failed_moves = {}
        for turn in history[-10:]:  # Last 10 turns
            if not turn.get("moved", False) and "action" in turn and turn["action"]["action"].startswith("MOVE_"):
                action = turn["action"]["action"]
                prev_pos = tuple(turn["state"]["player"]["position"])
                if action == "MOVE_RIGHT":
                    failed_moves[(prev_pos[0] + 3, prev_pos[1])] = failed_moves.get((prev_pos[0] + 3, prev_pos[1]), 0) + 1
                elif action == "MOVE_LEFT":
                    failed_moves[(prev_pos[0] - 3, prev_pos[1])] = failed_moves.get((prev_pos[0] - 3, prev_pos[1]), 0) + 1
                elif action == "MOVE_UP":
                    failed_moves[(prev_pos[0], prev_pos[1] - 3)] = failed_moves.get((prev_pos[0], prev_pos[1] - 3), 0) + 1
                elif action == "MOVE_DOWN":
                    failed_moves[(prev_pos[0], prev_pos[1] + 3)] = failed_moves.get((prev_pos[0], prev_pos[1] + 3), 0) + 1
        return {pos for pos, count in failed_moves.items() if count >= 3}  # Threshold for obstacles

    player_pos = tuple(state["player"]["position"])
    goals = state["objects"]["goals"]
    walls = {tuple(wall["position"]) for wall in state["objects"]["walls"]}
    blocks = {tuple(block["position"]) for block in state["objects"]["blocks"]}
    historical_obstacles = get_historical_obstacles(history)

    # Incorporate level-specific strategy for Level 1
    if state["level"]["current"] == 1:
        if player_pos == (3, 21) or player_pos == (0, 21):
            # Probe MOVE_DOWN even if blocked, as per strategy
            if not state["movement"]["down_blocked"] or (len(history) % 5 == 0):  # Probe every 5 turns if blocked
                return {"action": "MOVE_DOWN"}
            else:
                return {"action": "MOVE_LEFT"}  # Fallback
        else:
            # Move LEFT until reaching [3,21] or [0,21]
            if player_pos[0] > 0:
                return {"action": "MOVE_LEFT"}

    if goals and state["resources"]["steps_remaining"] > 10:  # Only pathfind if steps remain
        goal_pos = tuple(goals[0]["position"])
        path = a_star_search(player_pos, goal_pos, walls, blocks, historical_obstacles)

        if path:
            next_step = path[0]
            move_direction = get_move_direction(player_pos, next_step)
            if move_direction:
                return {"action": move_direction}

    if is_stuck(history):
        selectables = state["objects"]["selectables"]
        if selectables and goals:
            selectables_sorted = sorted(selectables, key=lambda s: min(heuristic(tuple(s["position"]), tuple(g["position"])) for g in goals))
            for selectable in selectables_sorted:
                sel_pos = tuple(selectable["position"])
                if sel_pos != player_pos:
                    # Quick check if path exists from selectable to goal
                    path = a_star_search(sel_pos, tuple(goals[0]["position"]), walls, blocks, historical_obstacles)
                    if path:
                        return {"action": "CLICK", "target_position": list(sel_pos)}

    # Fallback: Prioritize directions based on historical success
    success_count = {"MOVE_RIGHT": 0, "MOVE_LEFT": 0, "MOVE_UP": 0, "MOVE_DOWN": 0}
    for turn in history:
        if turn.get("moved", False) and "action" in turn and turn["action"]["action"] in success_count:
            success_count[turn["action"]["action"]] += 1

    if success_count:
        best_direction = max(success_count, key=success_count.get)
        # Check if the best direction is not blocked
        if (best_direction == "MOVE_RIGHT" and not state["movement"]["right_blocked"]) or \
           (best_direction == "MOVE_LEFT" and not state["movement"]["left_blocked"]) or \
           (best_direction == "MOVE_UP" and not state["movement"]["up_blocked"]) or \
           (best_direction == "MOVE_DOWN" and not state["movement"]["down_blocked"]):
            return {"action": best_direction}
        else:
            # Probe the best direction occasionally if blocked
            if len(history) % 4 == 0:  # Every 4 turns
                return {"action": best_direction}
            else:
                # Fallback to next best
                alternatives = sorted(success_count.items(), key=lambda x: x[1], reverse=True)
                for dir_name, _ in alternatives[1:]:  # Skip the best if blocked
                    if (dir_name == "MOVE_RIGHT" and not state["movement"]["right_blocked"]):
                        return {"action": dir_name}
                    elif (dir_name == "MOVE_LEFT" and not state["movement"]["left_blocked"]):
                        return {"action": dir_name}
                    elif (dir_name == "MOVE_UP" and not state["movement"]["up_blocked"]):
                        return {"action": dir_name}
                    elif (dir_name == "MOVE_DOWN" and not state["movement"]["down_blocked"]):
                        return {"action": dir_name}
    return {"action": "MOVE_RIGHT"}  # Ultimate fallback
